// Step 1: Re-assert both ensures-foralls over page_array so the triggers
// `post1_self_.page_array@[i]`, `post2_self_.page_array@[i]`, and
// `pre_self_.page_array@[i]` are jointly in scope. This is what z3 was missing
// at the file level — the two runs had disjoint triggers.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// Step 2: At the index, every field of post1 and post2 matches: addr, state,
// is_io_page, rev_pointer, ref_count, owning_container, io_mappings all go
// through pre_self_.page_array@[index]; mappings goes through `mapping` for
// both runs. Page is a plain struct, so field-wise equality lifts to value
// equality (`=~=`).
assert(post1_self_.page_array@[index as int] =~= post2_self_.page_array@[index as int]);

// Step 3: Pointwise equality of page_array@ across all valid indices, by case
// split on whether i is the modified index or one of the untouched ones.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Discharged by Step 2.
    } else {
        // Fire both foralls at this i; transitivity through pre_self_.page_array@[i].
        assert(post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
        assert(post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);
    }
}

// Step 4: Lift the pointwise equality to a Seq equality on page_array@.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
